import { onDestroy, onMount, signal } from '@vanrot/runtime';
import { bindSignalToScene, createWebglCanvasController } from './scene-preview.widget';

const color = signal('#ff5a3d');

onMount(() => {
  const canvas = document.querySelector('canvas');
  const container = canvas?.parentElement;

  if (!(canvas instanceof HTMLCanvasElement) || container === null) {
    return;
  }

  const controller = createWebglCanvasController({
    canvas,
    container,
    createRenderer(context) {
      return createAppOwnedThreeRenderer(context);
    },
    signalBindings: [
      bindSignalToScene(color, (nextColor) => material.color.set(nextColor)),
    ],
  });

  onDestroy(controller.destroy);
});

